using Frame.DataAccess;
using AutoMapper; using Frame.BusinessLogic.DTOs; using Frame.BusinessLogic.Interfaces; using Frame.Domain.Entities; using Microsoft.EntityFrameworkCore;  namespace Frame.BusinessLogic.Services {     public class FavoriteService : IFavoriteService     {         private readonly AppDbContext _context;         private readonly IMapper _mapper;          public FavoriteService(AppDbContext context, IMapper mapper)         {             _context = context;             _mapper = mapper;         }          public async Task<IEnumerable<FavoriteDto>> GetAllAsync()         {             var favorites = await _context.Favorites.ToListAsync();             return _mapper.Map<IEnumerable<FavoriteDto>>(favorites);         }          public async Task<IEnumerable<FavoriteDto>> GetByUserIdAsync(int userId)         {             var favorites = await _context.Favorites.Where(f => f.UserId == userId).ToListAsync();             return _mapper.Map<IEnumerable<FavoriteDto>>(favorites);         }          public async Task<FavoriteDto> CreateAsync(FavoriteDto favoriteDto)         {             var favorite = _mapper.Map<Favorite>(favoriteDto);             _context.Favorites.Add(favorite);             await _context.SaveChangesAsync();             return _mapper.Map<FavoriteDto>(favorite);         }          public async Task<bool> DeleteAsync(int id)         {             var favorite = await _context.Favorites.FindAsync(id);             if (favorite == null) return false;              _context.Favorites.Remove(favorite);             await _context.SaveChangesAsync();             return true;         }     } }
